import React, { useState, useEffect, useRef } from 'react';
import { io } from 'socket.io-client';
import Settings from './Settings';
import StatusViewer from './StatusViewer';

const socket = io('http://192.168.0.100:5001');
const API = 'http://192.168.0.100:5001';

function timeStr(d) {
  return d ? new Date(d).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

function avatarColor(name) {
  const colors = ['linear-gradient(135deg,#6366f1,#8b5cf6)', 'linear-gradient(135deg,#f59e0b,#ef4444)', 'linear-gradient(135deg,#10b981,#3b82f6)', 'linear-gradient(135deg,#ec4899,#8b5cf6)', 'linear-gradient(135deg,#14b8a6,#6366f1)'];
  return colors[(name?.charCodeAt(0) || 0) % colors.length];
}

export default function App() {
  const [screen, setScreen] = useState('loading');
  const [form, setForm] = useState({ username: '', email: '', password: '' });
  const [currentUser, setCurrentUser] = useState(null);
  const [token, setToken] = useState('');

  const [friends, setFriends] = useState([]);
  const [requests, setRequests] = useState([]);
  const [activeContact, setActiveContact] = useState(null);
  const [chats, setChats] = useState({});
  const [msg, setMsg] = useState('');
  const [smartReplies, setSmartReplies] = useState([]);
  const [warning, setWarning] = useState('');
  const [tab, setTab] = useState('chats');
  const [searchQ, setSearchQ] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [sentRequests, setSentRequests] = useState([]);
  const [notification, setNotification] = useState('');
  const [onlineFriends, setOnlineFriends] = useState([]);
  const [unread, setUnread] = useState({});
  const [showSettings, setShowSettings] = useState(false);
  const [replyingTo, setReplyingTo] = useState(null);
  const [showEmojiFor, setShowEmojiFor] = useState(null);
  const [showContactMenu, setShowContactMenu] = useState(false);
  const [msgContextMenu, setMsgContextMenu] = useState(null); // {msgId, x, y, seenAt}
  const [blockedList, setBlockedList] = useState([]);
  const [showStatus, setShowStatus] = useState(false);
  const [friendDetails, setFriendDetails] = useState({});
  const [statuses, setStatuses] = useState([]);
  const [statusUploading, setStatusUploading] = useState(false);
  const [statusText, setStatusText] = useState('');
  const [viewingStatus, setViewingStatus] = useState(null);
  const fileInputRef = useRef(null);
  const statusFileRef = useRef(null);

  const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);
  useEffect(() => {
    const handler = () => setIsMobile(window.innerWidth <= 768);
    window.addEventListener('resize', handler);
    return () => window.removeEventListener('resize', handler);
  }, []);

  const messagesEndRef = useRef(null);
  const currentUserRef = useRef(null);
  const activeContactRef = useRef(null);
  const chatsRef = useRef({});

  useEffect(() => { currentUserRef.current = currentUser; }, [currentUser]);
  useEffect(() => { activeContactRef.current = activeContact; }, [activeContact]);
  useEffect(() => { chatsRef.current = chats; }, [chats]);
  const smartReplyRef = useRef([]);
  useEffect(() => { smartReplyRef.current = smartReplies; }, [smartReplies]);

  const authFetch = (url, opts = {}) => fetch(API + url, { ...opts, headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}`, ...(opts.headers || {}) } });

  // restore session
  useEffect(() => {
    const savedToken = localStorage.getItem('chat_token');
    const savedUser = localStorage.getItem('chat_user');
    if (savedToken && savedUser) {
      const user = JSON.parse(savedUser);
      setToken(savedToken);
      setCurrentUser(user);
      socket.emit('register-online', user.username);
      if ('Notification' in window && Notification.permission === 'default') Notification.requestPermission();
      fetch(API + '/friends', { headers: { Authorization: `Bearer ${savedToken}` } })
        .then(r => r.json())
        .then(data => {
          setFriends(data.friends || []);
          setRequests(data.requests || []);
          const details = {};
          (data.friendDetails || []).forEach(f => { details[f.username] = f; });
          setFriendDetails(details);
          // restore last tab
          const savedTab = localStorage.getItem('chat_tab');
          if (savedTab) setTab(savedTab);
          setScreen('chat');
        })
        .catch(() => { localStorage.removeItem('chat_token'); localStorage.removeItem('chat_user'); setScreen('login'); });
    } else {
      setScreen('login');
    }
  }, []);

  // ALL socket listeners in ONE effect with no dependencies — use refs for current values
  useEffect(() => {
    socket.on('receiveMessage', (data) => {
      const me = currentUserRef.current?.username;
      const key = data.sender === me ? data.receiver : data.sender;
      setChats(prev => {
        const existing = prev[key] || [];
        if (existing.some(m => m._id && data._id && m._id.toString() === data._id.toString())) return prev;
        return { ...prev, [key]: [...existing, { ...data, time: timeStr(data.createdAt) }] };
      });
      // show browser notification if message is from someone else and app is not focused
      if (data.sender !== me) {
        // unread badge
        if (activeContactRef.current !== data.sender) {
          setUnread(prev => ({ ...prev, [data.sender]: (prev[data.sender] || 0) + 1 }));
        }
        // browser notification
        if (document.hidden && 'Notification' in window && Notification.permission === 'granted') {
          new Notification(`💬 ${data.sender}`, {
            body: data.text || '📎 Sent a file',
            icon: '/favicon.ico'
          });
        }
      }
    });

    socket.on('smartReplies', (replies) => {
      setSmartReplies(replies);
      setTimeout(() => setSmartReplies([]), 15000);
    });

    socket.on('warning', (w) => { setWarning(w); setTimeout(() => setWarning(''), 4000); });
    socket.on('error', (e) => { setWarning(e); setTimeout(() => setWarning(''), 4000); });

    socket.on('friendRequest', ({ from }) => {
      setRequests(prev => prev.includes(from) ? prev : [...prev, from]);
      setNotification(`👋 ${from} sent you a friend request!`);
      setTimeout(() => setNotification(''), 4000);
      // auto switch to requests tab
      setTab('requests');
    });

    socket.on('requestAccepted', ({ by }) => {
      setFriends(prev => prev.includes(by) ? prev : [...prev, by]);
      setNotification(`✅ ${by} accepted your friend request!`);
      setTimeout(() => setNotification(''), 4000);
    });

    socket.on('userOnline', (username) => setOnlineFriends(prev => [...new Set([...prev, username])]));
    socket.on('userOffline', (username) => setOnlineFriends(prev => prev.filter(u => u !== username)));
    socket.on('onlineFriendsList', (list) => setOnlineFriends(list));
    socket.on('messagesSeen', ({ by, at }) => {
      setChats(prev => {
        const updated = { ...prev };
        if (updated[by]) {
          updated[by] = updated[by].map(m =>
            m.sender === currentUserRef.current?.username && !m.seenAt ? { ...m, seenAt: at } : m
          );
        }
        return updated;
      });
    });
    socket.on('messageReaction', ({ msgId, reactions }) => {
      setChats(prev => {
        const updated = { ...prev };
        for (const key of Object.keys(updated)) {
          updated[key] = updated[key].map(m =>
            m._id?.toString() === msgId?.toString() ? { ...m, reactions } : m
          );
        }
        return updated;
      });
    });

    return () => {
      ['receiveMessage','smartReplies','warning','error','friendRequest','requestAccepted','userOnline','userOffline','onlineFriendsList','messageReaction','messagesSeen']
        .forEach(e => socket.off(e));
    };
  }, []); // empty deps — refs handle current values

  useEffect(() => { messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [chats, activeContact]);

  const loadFriends = async (tok) => {
    const t = tok || token;
    const res = await fetch(API + '/friends', { headers: { Authorization: `Bearer ${t}` } });
    const data = await res.json();
    setFriends(data.friends || []);
    setRequests(data.requests || []);
    const details = {};
    (data.friendDetails || []).forEach(f => { details[f.username] = f; });
    setFriendDetails(details);
    // load last message for each friend for preview
    (data.friends || []).forEach(async (f) => {
      const r = await fetch(API + `/messages/${f}`, { headers: { Authorization: `Bearer ${t}` } });
      const msgs = await r.json();
      if (Array.isArray(msgs) && msgs.length > 0) {
        setChats(prev => ({ ...prev, [f]: msgs.map(m => ({ ...m, time: timeStr(m.createdAt) })) }));
      }
    });
  };

  const loadStatuses = async (tok) => {
    const t = tok || token;
    const res = await fetch(API + '/statuses', { headers: { Authorization: `Bearer ${t}` } });
    const data = await res.json();
    setStatuses(Array.isArray(data) ? data : []);
  };

  const postStatus = async (type, file) => {
    setStatusUploading(true);
    const fd = new FormData();
    fd.append('type', type);
    if (type === 'text') fd.append('content', statusText);
    else fd.append('file', file);
    await fetch(API + '/status', { method: 'POST', headers: { Authorization: `Bearer ${token}` }, body: fd });
    setStatusUploading(false);
    setStatusText('');
    loadStatuses();
  };

  const loadHistory = async (username) => {
    if (!username) return;
    const res = await authFetch(`/messages/${username}`);
    const data = await res.json();
    if (Array.isArray(data)) setChats(prev => ({ ...prev, [username]: data.map(m => ({ ...m, time: timeStr(m.createdAt) })) }));
  };

  const handleAuth = async (e) => {
    e.preventDefault(); setAuthError('');
    const endpoint = screen === 'login' ? '/login' : '/register';
    const body = screen === 'login' ? { email: form.email, password: form.password } : form;
    try {
      const res = await fetch(API + endpoint, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) });
      const data = await res.json();
      if (!res.ok) { setAuthError(data.error || data.errors?.[0]?.msg || 'Something went wrong'); return; }
      if (screen === 'register') { setScreen('login'); setForm(f => ({ ...f, password: '' })); return; }
      setToken(data.token);
      setCurrentUser(data.user);
      localStorage.setItem('chat_token', data.token);
      localStorage.setItem('chat_user', JSON.stringify(data.user));
      socket.emit('register-online', data.user.username);
      // request notification permission
      if ('Notification' in window && Notification.permission === 'default') {
        Notification.requestPermission();
      }
      await loadFriends(data.token);
      setScreen('chat');
    } catch { setAuthError('Server not reachable. Make sure backend is running.'); }
  };

  const handleSearch = async (q) => {
    setSearchQ(q);
    if (!q.trim()) { setSearchResults([]); return; }
    const res = await authFetch(`/users/search?q=${encodeURIComponent(q)}`);
    const data = await res.json();
    setSearchResults(Array.isArray(data) ? data : []);
  };

  const sendRequest = async (username) => {
    await authFetch('/friends/request', { method: 'POST', body: JSON.stringify({ toUsername: username }) });
    setSentRequests(prev => [...prev, username]);
  };

  const acceptRequest = async (username) => {
    await authFetch('/friends/accept', { method: 'POST', body: JSON.stringify({ fromUsername: username }) });
    setRequests(prev => prev.filter(r => r !== username));
    setFriends(prev => [...prev, username]);
  };

  const rejectRequest = async (username) => {
    await authFetch('/friends/reject', { method: 'POST', body: JSON.stringify({ fromUsername: username }) });
    setRequests(prev => prev.filter(r => r !== username));
  };

  const openChat = async (username) => {
    setActiveContact(username);
    setTab('chats');
    setSmartReplies([]); setWarning('');
    setUnread(prev => ({ ...prev, [username]: 0 }));
    if (!chats[username]) await loadHistory(username);
    // mark messages as seen
    authFetch('/messages/seen', { method: 'POST', body: JSON.stringify({ senderUsername: username }) });
    // fetch fresh details for this friend (profile pic + last seen)
    fetch(API + '/user/' + username, { headers: { Authorization: `Bearer ${token}` } })
      .then(r => r.json())
      .then(data => { if (data.username) setFriendDetails(prev => ({ ...prev, [username]: data })); });
  };

  const send = (text) => {
    const t = text || msg;
    if (!t.trim() || !activeContact) return;
    socket.emit('sendMessage', { sender: currentUser.username, receiver: activeContact, text: t, replyTo: replyingTo ? { _id: replyingTo._id, sender: replyingTo.sender, text: replyingTo.text, fileType: replyingTo.fileType } : null });
    setMsg('');
    setSmartReplies([]);
    setReplyingTo(null);
    smartReplyRef.current = [];
  };

  const handleKey = (e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send(); } };

  const lastSeenStr = (username) => {
    if (onlineFriends.includes(username)) return null;
    const d = friendDetails[username];
    if (!d || !d.lastSeen) return 'Offline';
    const diff = Date.now() - new Date(d.lastSeen);
    const m = Math.floor(diff / 60000);
    const h = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);
    if (m < 1) return 'Last seen just now';
    if (h < 1) return `Last seen ${m}m ago`;
    if (days < 1) return `Last seen ${h}h ago`;
    return `Last seen ${days}d ago`;
  };

  const unfriend = async (username) => {
    await authFetch('/friends/unfriend', { method: 'POST', body: JSON.stringify({ username }) });
    setFriends(prev => prev.filter(f => f !== username));
    setActiveContact(null);
    setShowContactMenu(false);
  };

  const blockUser = async (username) => {
    await authFetch('/friends/block', { method: 'POST', body: JSON.stringify({ username }) });
    setFriends(prev => prev.filter(f => f !== username));
    setBlockedList(prev => [...prev, username]);
    setActiveContact(null);
    setShowContactMenu(false);
  };

  const unblockUser = async (username) => {
    await authFetch('/friends/unblock', { method: 'POST', body: JSON.stringify({ username }) });
    setBlockedList(prev => prev.filter(b => b !== username));
  };

  const reactToMsg = async (msgId, emoji) => {
    setShowEmojiFor(null);
    const res = await authFetch(`/messages/${msgId}/react`, { method: 'POST', body: JSON.stringify({ emoji }) });
    const data = await res.json();
    if (data.reactions) {
      setChats(prev => {
        const updated = { ...prev };
        for (const key of Object.keys(updated)) {
          updated[key] = updated[key].map(m =>
            m._id?.toString() === msgId?.toString() ? { ...m, reactions: data.reactions } : m
          );
        }
        return updated;
      });
    }
  };

  const sendFile = async (file) => {
    if (!file || !activeContact) return;
    const fd = new FormData();
    fd.append('file', file);
    const res = await fetch(API + '/upload/chat', {
      method: 'POST',
      headers: { Authorization: `Bearer ${token}` },
      body: fd
    });
    const data = await res.json();
    if (data.fileUrl) {
      socket.emit('sendMessage', { sender: currentUser.username, receiver: activeContact, text: '', fileUrl: data.fileUrl, fileType: data.fileType, fileName: data.fileName });
    }
  };

  // on input focus — show suggestion based on last received message
  const handleFocus = () => {
    if (smartReplyRef.current.length) return;
    const contact = activeContactRef.current;
    const me = currentUserRef.current?.username;
    if (!contact || !me) return;
    const msgs = chatsRef.current[contact] || [];
    if (!msgs.length) return;
    const lastMsg = msgs[msgs.length - 1];
    console.log('handleFocus - me:', me, 'lastMsg.sender:', lastMsg.sender, 'text:', lastMsg.text);
    if (lastMsg.sender === me) return;
    socket.emit('getSuggestion', { text: lastMsg.text, requester: me });
  };

  const activeMessages = chats[activeContact] || [];

  const s = {
    wrap: { display:'flex', height:'100vh', height:'-webkit-fill-available', width:'100vw', overflow:'hidden', background:'#0f0f13', fontFamily:'Inter,sans-serif' },
    authWrap: { display:'flex', alignItems:'center', justifyContent:'center', width:'100%', height:'100vh', background:'linear-gradient(135deg,#0f0f13,#1a1a2e)', padding:'0 16px', boxSizing:'border-box' },
    authBox: { background:'#1e1e2e', border:'1px solid #2d2d3f', borderRadius:16, padding:'32px 24px', width:'100%', maxWidth:400, boxShadow:'0 24px 64px rgba(0,0,0,.5)' },
    authTitle: { fontSize:26, fontWeight:700, marginBottom:6, background:'linear-gradient(90deg,#818cf8,#c084fc)', WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent' },
    authSub: { fontSize:13, color:'#64748b', marginBottom:28 },
    inp: { width:'100%', padding:'11px 14px', background:'#12121a', border:'1px solid #2d2d3f', borderRadius:10, color:'#e2e8f0', fontSize:14, marginBottom:12, outline:'none', boxSizing:'border-box' },
    authBtn: { width:'100%', padding:12, background:'linear-gradient(90deg,#6366f1,#8b5cf6)', border:'none', borderRadius:10, color:'#fff', fontWeight:600, fontSize:15, cursor:'pointer', marginTop:4 },
    authToggle: { textAlign:'center', marginTop:18, fontSize:13, color:'#64748b' },
    authToggleBtn: { background:'none', border:'none', color:'#818cf8', cursor:'pointer', fontWeight:600, fontSize:13 },
    authError: { background:'#2d1b1b', border:'1px solid #7f1d1d', borderRadius:8, padding:'10px 14px', fontSize:13, color:'#fca5a5', marginBottom:14 },
    sidebar: { width: isMobile ? '100vw' : 280, minWidth: isMobile ? '100vw' : 280, height:'100vh', background:'#16161f', borderRight:'1px solid #1e1e2e', display: isMobile && activeContact ? 'none' : 'flex', flexDirection:'column', position: isMobile ? 'fixed' : 'relative', top:0, left:0, zIndex:10 },
    sidebarTop: { padding: isMobile ? '12px 14px' : '18px 16px 12px', borderBottom:'1px solid #1e1e2e', paddingTop: isMobile ? 'max(12px, env(safe-area-inset-top))' : '18px' },
    appName: { fontSize:18, fontWeight:700, background:'linear-gradient(90deg,#818cf8,#c084fc)', WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent' },
    myName: { fontSize:12, color:'#64748b', marginTop:3 },
    tabs: { display:'flex', padding:'10px 12px', gap:6, borderBottom:'1px solid #1e1e2e' },
    tabBtn: (a) => ({ flex:1, padding:'7px 4px', background:a?'#312e81':'transparent', border:'1px solid '+(a?'#4338ca':'#2d2d3f'), borderRadius:8, color:a?'#a5b4fc':'#64748b', fontSize:12, fontWeight:600, cursor:'pointer', position:'relative' }),
    badge: { position:'absolute', top:-4, right:-4, background:'#ef4444', color:'#fff', fontSize:9, fontWeight:700, borderRadius:10, padding:'1px 5px', minWidth:16, textAlign:'center' },
    searchBox: { padding:'10px 12px', borderBottom:'1px solid #1e1e2e' },
    searchInp: { width:'100%', padding:'9px 12px', background:'#12121a', border:'1px solid #2d2d3f', borderRadius:10, color:'#e2e8f0', fontSize:13, outline:'none', boxSizing:'border-box' },
    listArea: { flex:1, overflowY:'auto' },
    item: (a) => ({ display:'flex', alignItems:'center', gap:10, padding:'10px 14px', cursor:'pointer', background:a?'#1e1e2e':'transparent', borderLeft:a?'3px solid #6366f1':'3px solid transparent' }),
    avatar: (bg) => ({ width:38, height:38, borderRadius:'50%', background:bg, display:'flex', alignItems:'center', justifyContent:'center', fontWeight:700, fontSize:15, flexShrink:0, color:'#fff' }),
    itemName: { fontSize:14, fontWeight:500, color:'#cbd5e1' },
    itemSub: { fontSize:11, color:'#475569', marginTop:2 },
    onlineDot: { width:8, height:8, borderRadius:'50%', background:'#22c55e', display:'inline-block', marginRight:4 },
    actionBtns: { display:'flex', gap:6, marginTop:4 },
    acceptBtn: { padding:'4px 10px', background:'#14532d', border:'1px solid #16a34a', borderRadius:6, color:'#4ade80', fontSize:11, cursor:'pointer', fontWeight:600 },
    rejectBtn: { padding:'4px 10px', background:'#2d1b1b', border:'1px solid #7f1d1d', borderRadius:6, color:'#f87171', fontSize:11, cursor:'pointer', fontWeight:600 },
    sendReqBtn: (sent) => ({ padding:'5px 12px', background:sent?'#1e293b':'linear-gradient(90deg,#6366f1,#8b5cf6)', border:'none', borderRadius:8, color:sent?'#475569':'#fff', fontSize:12, cursor:sent?'default':'pointer', fontWeight:600, marginLeft:'auto', flexShrink:0 }),
    emptyState: { padding:'30px 16px', textAlign:'center', color:'#334155', fontSize:13 },
    logoutBtn: { margin:'12px', padding:'10px', background:'#1e1e2e', border:'1px solid #2d2d3f', borderRadius:10, color:'#94a3b8', cursor:'pointer', fontSize:13, fontWeight:500 },
    chatArea: { flex:1, minWidth:0, width: isMobile ? '100vw' : 'auto', height:'100vh', display: isMobile && !activeContact ? 'none' : 'flex', flexDirection:'column', background:'#0f0f13', overflow:'hidden', position: isMobile ? 'fixed' : 'relative', top:0, left:0, right:0, bottom:0 },
    chatHeader: { padding: isMobile ? '10px 12px' : '14px 20px', background:'#16161f', borderBottom:'1px solid #1e1e2e', display:'flex', alignItems:'center', gap: isMobile ? 8 : 12, flexShrink:0, paddingTop: isMobile ? 'max(10px, env(safe-area-inset-top))' : '14px' },
    chatHeaderName: { fontWeight:600, fontSize: isMobile ? 14 : 15, color:'#e2e8f0' },
    messages: { flex:1, minHeight:0, overflowY:'auto', padding: isMobile ? '12px' : '20px', display:'flex', flexDirection:'column', gap:10, WebkitOverflowScrolling:'touch' },
    emptyChat: { flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', color:'#334155', gap:8 },
    msgRow: (mine) => ({ display:'flex', justifyContent:mine?'flex-end':'flex-start', alignItems:'flex-end', gap:8, width:'100%' }),
    bubbleWrap: { maxWidth:'70%', display:'inline-flex', flexDirection:'column' },
    bubble: (mine) => ({ display:'inline-block', padding:'10px 14px', borderRadius:mine?'18px 18px 4px 18px':'18px 18px 18px 4px', background:mine?'linear-gradient(135deg,#6366f1,#8b5cf6)':'#1e1e2e', border:mine?'none':'1px solid #2d2d3f', color:'#e2e8f0', fontSize:14, lineHeight:1.6, wordBreak:'normal', overflowWrap:'break-word', whiteSpace:'pre-wrap' }),
    msgMeta: (mine) => ({ display:'flex', alignItems:'center', gap:6, marginTop:4, justifyContent:mine?'flex-end':'flex-start', flexWrap:'wrap' }),
    msgTime: { fontSize:10, color:'#475569' },
    sentimentBadge: (s) => { const m={'Positive 😊':['#14532d','#4ade80'],'Negative 😡':['#7f1d1d','#f87171'],'Neutral 😐':['#1e3a5f','#60a5fa']}; const [bg,c]=m[s]||['#1e293b','#94a3b8']; return {background:bg,color:c,fontSize:10,padding:'2px 7px',borderRadius:20,fontWeight:600}; },
    smartReplyBar: { margin:'0 20px 10px', padding:'8px 12px', background:'#1a1a2e', border:'1px solid #312e81', borderRadius:12, display:'flex', alignItems:'center', gap:8, flexShrink:0 },
    warningBanner: { margin:'0 20px 10px', padding:'10px 14px', background:'#2d1b00', border:'1px solid #92400e', borderRadius:12, fontSize:13, color:'#fbbf24', flexShrink:0 },
    notifBanner: { margin:'0 20px 10px', padding:'10px 14px', background:'#1a2e1a', border:'1px solid #166534', borderRadius:12, fontSize:13, color:'#4ade80', flexShrink:0 },
    inputArea: { position:'relative', padding: isMobile ? '8px 12px' : '14px 20px', background:'#16161f', borderTop:'1px solid #1e1e2e', display:'flex', gap:8, alignItems:'flex-end', flexShrink:0, paddingBottom: isMobile ? 'max(8px, env(safe-area-inset-bottom))' : '14px' },
    inputBox: { flex:1, minWidth:0, padding: isMobile ? '10px 12px' : '11px 14px', background:'#12121a', border:'1px solid #2d2d3f', borderRadius:12, color:'#e2e8f0', fontSize:14, outline:'none', resize:'none', fontFamily:'Inter,sans-serif', lineHeight:1.5, maxHeight:100, overflowY:'auto', width:'100%', boxSizing:'border-box' },
    sendBtn: (a) => ({ padding: isMobile ? '10px 14px' : '11px 18px', background:a?'linear-gradient(135deg,#6366f1,#8b5cf6)':'#1e1e2e', border:'1px solid '+(a?'transparent':'#2d2d3f'), borderRadius:12, color:a?'#fff':'#475569', cursor:a?'pointer':'default', fontWeight:600, fontSize:14, flexShrink:0 }),
    noChatWrap: { flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', color:'#334155', gap:10 },
  };

  if (screen === 'loading') return (
    <div style={{...s.authWrap, flexDirection:'column', gap:12}}>
      <div style={{fontSize:40}}>💬</div>
      <div style={{color:'#64748b', fontSize:14}}>Loading...</div>
    </div>
  );

  if (screen === 'login' || screen === 'register') return (
    <div style={s.authWrap}>
      <div style={s.authBox}>
        <div style={s.authTitle}>💬 AI Chat App</div>
        <div style={s.authSub}>{screen==='login'?'Welcome back! Sign in to continue.':'Create your account to get started.'}</div>
        {authError && <div style={s.authError}>⚠️ {authError}</div>}
        <form onSubmit={handleAuth}>
          {screen==='register' && <input style={s.inp} placeholder="Username" value={form.username} onChange={e=>setForm(f=>({...f,username:e.target.value}))} required />}
          <input style={s.inp} type="email" placeholder="Email" value={form.email} onChange={e=>setForm(f=>({...f,email:e.target.value}))} required />
          <input style={s.inp} type="password" placeholder="Password (min 6 chars)" value={form.password} onChange={e=>setForm(f=>({...f,password:e.target.value}))} required />
          <button type="submit" style={s.authBtn}>{screen==='login'?'Sign In':'Create Account'}</button>
        </form>
        <div style={s.authToggle}>
          {screen==='login'?"Don't have an account? ":"Already have an account? "}
          <button style={s.authToggleBtn} onClick={()=>{setScreen(screen==='login'?'register':'login');setAuthError('');}}>
            {screen==='login'?'Register':'Sign In'}
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div style={s.wrap}>
      {showSettings && <Settings currentUser={currentUser} token={token} onClose={() => setShowSettings(false)} onUpdate={(user, tok) => { setCurrentUser(user); setToken(tok); localStorage.setItem('chat_token', tok); localStorage.setItem('chat_user', JSON.stringify(user)); }} />}
      {showStatus && <StatusViewer token={token} currentUser={currentUser} onClose={() => setShowStatus(false)} />}
      {/* Status fullscreen viewer */}
      {viewingStatus && (
        <div style={{ position:'fixed', inset:0, background:'#000', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', zIndex:2000 }}>
          <button onClick={()=>setViewingStatus(null)} style={{ position:'absolute', top:16, right:20, background:'none', border:'none', color:'#fff', fontSize:26, cursor:'pointer' }}>✕</button>
          <div style={{ position:'absolute', top:20, left:20, color:'#fff', fontSize:14, fontWeight:600 }}>{viewingStatus.username === currentUser?.username ? 'My Status' : viewingStatus.username}</div>
          {/* Views count for own status */}
          {viewingStatus.username === currentUser?.username && (
            <div style={{ position:'absolute', bottom:30, left:0, right:0, textAlign:'center' }}>
              <div style={{ display:'inline-flex', alignItems:'center', gap:6, background:'rgba(255,255,255,0.1)', padding:'8px 16px', borderRadius:20 }}>
                <span style={{ fontSize:16 }}>👁️</span>
                <span style={{ color:'#fff', fontSize:13, fontWeight:600 }}>{viewingStatus.status.views?.length || 0} views</span>
                {viewingStatus.status.views?.length > 0 && (
                  <span style={{ color:'#94a3b8', fontSize:12 }}>({viewingStatus.status.views.join(', ')})</span>
                )}
              </div>
            </div>
          )}
          <div style={{ maxWidth:500, width:'100%', textAlign:'center', padding:20 }}>
            {viewingStatus.status.type==='text' && <div style={{ fontSize:26, color:'#fff', fontWeight:600, lineHeight:1.5 }}>{viewingStatus.status.content}</div>}
            {viewingStatus.status.type==='image' && <img src={viewingStatus.status.fileUrl} alt="status" style={{ maxWidth:'100%', maxHeight:'70vh', borderRadius:12 }} />}
            {viewingStatus.status.type==='video' && <video src={viewingStatus.status.fileUrl} controls autoPlay style={{ maxWidth:'100%', maxHeight:'70vh', borderRadius:12 }} />}
            {viewingStatus.status.type==='audio' && <audio src={viewingStatus.status.fileUrl} controls autoPlay style={{ width:'100%' }} />}
          </div>
        </div>
      )}
      {/* Search overlay */}
      {tab==='search' && (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.7)', zIndex:500, display:'flex', alignItems:'flex-start', justifyContent:'center', paddingTop:80 }} onClick={()=>{ setTab('chats'); setSearchQ(''); setSearchResults([]); }}>
          <div style={{ background:'#1e1e2e', border:'1px solid #2d2d3f', borderRadius:16, width: isMobile ? '92vw' : 400, maxHeight:'70vh', overflow:'hidden', display:'flex', flexDirection:'column' }} onClick={e=>e.stopPropagation()}>
            <div style={{ padding:'14px 16px', borderBottom:'1px solid #2d2d3f' }}>
              <input style={{ width:'100%', padding:'10px 14px', background:'#12121a', border:'1px solid #2d2d3f', borderRadius:10, color:'#e2e8f0', fontSize:14, outline:'none', boxSizing:'border-box' }}
                placeholder="Search by username..." value={searchQ} onChange={e=>handleSearch(e.target.value)} autoFocus />
            </div>
            <div style={{ overflowY:'auto', flex:1 }}>
              {searchQ && searchResults.length===0 && <div style={s.emptyState}>No users found</div>}
              {searchResults.map(u=>(
                <div key={u._id} style={{...s.item(false), alignItems:'center'}}>
                  {u.profilePic && u.profilePic.length > 0
                    ? <img src={u.profilePic} alt="pfp" style={{ width:38, height:38, borderRadius:'50%', objectFit:'cover', flexShrink:0 }} />
                    : <div style={s.avatar(avatarColor(u.username))}>{u.username[0].toUpperCase()}</div>
                  }
                  <div style={{flex:1}}>
                    <div style={s.itemName}>{u.username}</div>
                    <div style={s.itemSub}>{friends.includes(u.username)?'✅ Friends':'Send a request'}</div>
                  </div>
                  {!friends.includes(u.username) && (
                    <button style={s.sendReqBtn(sentRequests.includes(u.username))} onClick={()=>{ if(!sentRequests.includes(u.username)) sendRequest(u.username); }}>
                      {sentRequests.includes(u.username)?'Sent':'Add'}
                    </button>
                  )}
                </div>
              ))}
              {!searchQ && <div style={s.emptyState}>Type a username to search</div>}
            </div>
          </div>
        </div>
      )}
      <div style={s.sidebar}>
        <div style={s.sidebarTop}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
            <div style={s.appName}>💬 ChatAI</div>
            <div style={{ display:'flex', gap:6 }}>
              <button onClick={() => setTab('search')} style={{ background:'none', border:'none', fontSize:18, cursor:'pointer' }} title="Search">🔍</button>
              <button onClick={() => setShowSettings(true)} style={{ background:'none', border:'none', fontSize:18, cursor:'pointer' }} title="Settings">⚙️</button>
            </div>
          </div>
          <div style={{ display:'flex', alignItems:'center', gap:8, marginTop:6 }}>
            {currentUser?.profilePic
              ? <img src={currentUser.profilePic} alt="pfp" style={{ width:28, height:28, borderRadius:'50%', objectFit:'cover' }} />
              : <div style={{ width:28, height:28, borderRadius:'50%', background:'linear-gradient(135deg,#6366f1,#8b5cf6)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:12, fontWeight:700, color:'#fff' }}>{currentUser?.username?.[0]?.toUpperCase()}</div>
            }
            <div style={s.myName}>👤 {currentUser?.username}</div>
          </div>
        </div>
        <div style={s.tabs}>
          {[['chats','💬 Chats'],['status','📸 Status'],['requests','🔔 Requests']].map(([key,label])=>(
            <button key={key} style={s.tabBtn(tab===key)} onClick={()=>{ setTab(key); localStorage.setItem('chat_tab',key); if(key==='status') loadStatuses(); }}>
              {label}
              {key==='requests' && requests.length>0 && <span style={s.badge}>{requests.length}</span>}
            </button>
          ))}
        </div>
        <div style={s.listArea}>
          {tab==='chats' && (
            friends.length===0
              ? <div style={s.emptyState}>No friends yet.<br/>Search users to add friends!</div>
              : friends.map(f=>(
                <div key={f} style={s.item(activeContact===f)} onClick={()=>openChat(f)}>
                  {friendDetails[f]?.profilePic
                    ? <img src={friendDetails[f].profilePic} alt="pfp" style={{ width:38, height:38, borderRadius:'50%', objectFit:'cover', flexShrink:0 }} />
                    : <div style={s.avatar(avatarColor(f))}>{f[0].toUpperCase()}</div>
                  }
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                      <div style={s.itemName}>{f}</div>
                      {chats[f]?.length > 0 && <span style={{ fontSize:10, color:'#475569', flexShrink:0 }}>{chats[f][chats[f].length-1].time}</span>}
                    </div>
                    <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                      <div style={{ fontSize:11, color: unread[f]>0 ? '#a5b4fc' : '#475569', marginTop:2, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', maxWidth:160 }}>
                        {chats[f]?.length > 0
                          ? (chats[f][chats[f].length-1].fileType === 'image' ? '📷 Photo'
                            : chats[f][chats[f].length-1].fileType === 'video' ? '🎬 Video'
                            : chats[f][chats[f].length-1].fileType === 'audio' ? '🎵 Audio'
                            : chats[f][chats[f].length-1].fileType === 'file' ? '📎 File'
                            : chats[f][chats[f].length-1].text || '')
                          : onlineFriends.includes(f) ? <><span style={s.onlineDot}/>Online</> : 'Offline'}
                      </div>
                      {unread[f] > 0 && <span style={{ background:'#6366f1', color:'#fff', fontSize:10, fontWeight:700, borderRadius:10, padding:'2px 7px', flexShrink:0 }}>{unread[f]}</span>}
                    </div>
                  </div>
                </div>
              ))
          )}
          {tab==='search' && (
            <>
              <div style={s.searchBox}>
                <input style={s.searchInp} placeholder="Search by username..." value={searchQ} onChange={e=>handleSearch(e.target.value)} autoFocus />
              </div>
              {searchQ && searchResults.length===0 && <div style={s.emptyState}>No users found</div>}
              {searchResults.map(u=>(
                <div key={u._id} style={{...s.item(false), alignItems:'center'}}>
                  <div style={s.avatar(avatarColor(u.username))}>{u.username[0].toUpperCase()}</div>
                  <div style={{flex:1}}>
                    <div style={s.itemName}>{u.username}</div>
                    <div style={s.itemSub}>{friends.includes(u.username)?'✅ Friends':'Send a request'}</div>
                  </div>
                  {!friends.includes(u.username) && (
                    <button style={s.sendReqBtn(sentRequests.includes(u.username))} onClick={()=>!sentRequests.includes(u.username)&&sendRequest(u.username)}>
                      {sentRequests.includes(u.username)?'Sent':'Add'}
                    </button>
                  )}
                </div>
              ))}
              {!searchQ && <div style={s.emptyState}>Type a username to search</div>}
            </>
          )}
          {tab==='status' && (
            <>
              {/* Add status */}
              <div style={{ padding:'12px 14px', borderBottom:'1px solid #1e1e2e' }}>
                <div style={{ fontSize:11, color:'#475569', fontWeight:600, marginBottom:8, textTransform:'uppercase', letterSpacing:1 }}>My Status</div>
                <textarea
                  style={{ width:'100%', padding:'9px 12px', background:'#12121a', border:'1px solid #2d2d3f', borderRadius:10, color:'#e2e8f0', fontSize:13, outline:'none', resize:'none', fontFamily:'Inter,sans-serif', boxSizing:'border-box', marginBottom:8 }}
                  rows={2} placeholder="Write a status..." value={statusText} onChange={e=>setStatusText(e.target.value)}
                />
                <div style={{ display:'flex', gap:6, flexWrap:'wrap' }}>
                  {statusText.trim() && (
                    <button onClick={()=>postStatus('text')} style={{ padding:'6px 12px', background:'linear-gradient(90deg,#6366f1,#8b5cf6)', border:'none', borderRadius:8, color:'#fff', fontSize:12, cursor:'pointer', fontWeight:600 }}>
                      {statusUploading ? 'Posting...' : 'Post ✏️'}
                    </button>
                  )}
                  <input ref={statusFileRef} type="file" style={{ display:'none' }} onChange={e=>{ const f=e.target.files[0]; if(!f) return; const t=f.type.startsWith('image')?'image':f.type.startsWith('video')?'video':'audio'; postStatus(t,f); e.target.value=''; }} />
                  {[{icon:'🖼️',label:'Photo',accept:'image/*'},{icon:'🎬',label:'Video',accept:'video/*'},{icon:'🎵',label:'Audio',accept:'audio/*'}].map(({icon,label,accept})=>(
                    <button key={label} onClick={()=>{ statusFileRef.current.accept=accept; statusFileRef.current.click(); }}
                      style={{ padding:'6px 10px', background:'#1e1e2e', border:'1px solid #2d2d3f', borderRadius:8, color:'#94a3b8', fontSize:12, cursor:'pointer' }}>
                      {icon}
                    </button>
                  ))}
                </div>
              </div>
              {/* View statuses */}
              <div style={{ flex:1, overflowY:'auto' }}>
                {statuses.length===0
                  ? <div style={s.emptyState}>No statuses yet</div>
                  : statuses.map(u=>(
                    <div key={u.username} style={{ padding:'10px 14px', borderBottom:'1px solid #1e1e2e' }}>
                      <div style={{ fontSize:11, color:'#475569', fontWeight:600, marginBottom:6 }}>
                        {u.username === currentUser?.username ? '👤 My Status' : u.username}
                      </div>
                      <div style={{ display:'flex', gap:8, flexWrap:'wrap' }}>
                        {u.statuses.map((st,i)=>(
                          <div key={i} onClick={()=>{
                            setViewingStatus({username:u.username,status:st});
                            // mark as viewed if not own status
                            if(u.username !== currentUser?.username && st._id) {
                              fetch(`${API}/status/${u.username}/${st._id}/view`, {
                                method:'POST', headers:{ Authorization:`Bearer ${token}` }
                              }).then(r=>r.json()).then(data=>{
                                // update views in local state
                                setStatuses(prev => prev.map(user => user.username===u.username ? {
                                  ...user, statuses: user.statuses.map(s => s._id===st._id ? {...s, views: data.views} : s)
                                } : user));
                              });
                            }
                          }}
                            style={{ width:56, height:56, borderRadius:10, background:'#12121a', border:'2px solid #6366f1', cursor:'pointer', overflow:'hidden', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                            {st.type==='text' && <div style={{ fontSize:9, color:'#c7d2fe', padding:3, textAlign:'center', overflow:'hidden', lineHeight:1.3 }}>{st.content?.slice(0,20)}</div>}
                            {st.type==='image' && <img src={st.fileUrl} alt="" style={{ width:'100%', height:'100%', objectFit:'cover' }} />}
                            {st.type==='video' && <div style={{ fontSize:18 }}>🎬</div>}
                            {st.type==='audio' && <div style={{ fontSize:18 }}>🎵</div>}
                          </div>
                        ))}
                      </div>
                    </div>
                  ))
                }
              </div>
            </>
          )}
          {tab==='requests' && (
            requests.length===0
              ? <div style={s.emptyState}>No pending requests</div>
              : requests.map(r=>(
                <div key={r} style={s.item(false)}>
                  <div style={s.avatar(avatarColor(r))}>{r[0].toUpperCase()}</div>
                  <div>
                    <div style={s.itemName}>{r}</div>
                    <div style={s.actionBtns}>
                      <button style={s.acceptBtn} onClick={()=>acceptRequest(r)}>✓ Accept</button>
                      <button style={s.rejectBtn} onClick={()=>rejectRequest(r)}>✕ Reject</button>
                    </div>
                  </div>
                </div>
              ))
          )}
        </div>
        <button style={s.logoutBtn} onClick={()=>{
          socket.emit('logout', currentUser?.username);
          socket.disconnect(); socket.connect();
          localStorage.removeItem('chat_token'); localStorage.removeItem('chat_user'); localStorage.removeItem('chat_tab');
          setScreen('login'); setCurrentUser(null); setToken(''); setChats({});
          setFriends([]); setRequests([]); setActiveContact(null); setSentRequests([]);
          setSmartReplies([]); setWarning(''); setNotification(''); setSearchQ('');
          setSearchResults([]); setTab('chats'); setOnlineFriends([]);
          setForm({ username: '', email: '', password: '' });
        }}>🚪 Sign Out</button>
      </div>

      <div style={s.chatArea}>
        {!activeContact ? (
          <div style={s.noChatWrap}>
            <div style={{fontSize:52}}>💬</div>
            <div style={{fontSize:16, fontWeight:600, color:'#475569'}}>Select a friend to start chatting</div>
            <div style={{fontSize:13, color:'#334155'}}>Search users → Add friends → Chat!</div>
          </div>
        ) : (
          <>
            <div style={s.chatHeader}>
              {isMobile && (
                <button onClick={()=>setActiveContact(null)} style={{ background:'none', border:'none', color:'#a5b4fc', fontSize:22, cursor:'pointer', padding:'0 4px', flexShrink:0 }}>←</button>
              )}
              {friendDetails[activeContact]?.profilePic && friendDetails[activeContact].profilePic.length > 0
                ? <img src={friendDetails[activeContact].profilePic} alt="pfp" style={{ width:38, height:38, borderRadius:'50%', objectFit:'cover', flexShrink:0 }} />
                : <div style={s.avatar(avatarColor(activeContact))}>{activeContact[0].toUpperCase()}</div>
              }
              <div style={{ flex:1 }}>
                <div style={s.chatHeaderName}>{activeContact}</div>
                <div style={{ fontSize:12 }}>
                  {onlineFriends.includes(activeContact)
                    ? <span style={{ color:'#22c55e' }}><span style={s.onlineDot}/>Online • AI-powered</span>
                    : <span style={{ color:'#475569' }}>{lastSeenStr(activeContact) || 'Offline'}</span>}
                </div>
              </div>
              {/* 3-dot menu */}
              <div style={{ position:'relative', flexShrink:0 }}>
                <button onClick={()=>setShowContactMenu(p=>!p)} style={{ background:'none', border:'none', color:'#64748b', fontSize:20, cursor:'pointer', padding:'4px 8px' }}>⋮</button>
                {showContactMenu && (
                  <div style={{ position:'absolute', right:0, top:36, background:'#1e1e2e', border:'1px solid #2d2d3f', borderRadius:10, minWidth:160, zIndex:100, boxShadow:'0 8px 24px rgba(0,0,0,.4)' }} onClick={()=>setShowContactMenu(false)}>
                    <button onClick={()=>unfriend(activeContact)} style={{ width:'100%', padding:'11px 16px', background:'none', border:'none', color:'#f87171', fontSize:13, cursor:'pointer', textAlign:'left', borderBottom:'1px solid #2d2d3f' }}>👤 Unfriend</button>
                    <button onClick={()=>blockUser(activeContact)} style={{ width:'100%', padding:'11px 16px', background:'none', border:'none', color:'#fbbf24', fontSize:13, cursor:'pointer', textAlign:'left' }}>🚫 Block</button>
                  </div>
                )}
              </div>
            </div>

            <div style={s.messages}>
              {activeMessages.length===0
                ? <div style={s.emptyChat}><div style={{fontSize:40}}>👋</div><div>No messages yet. Say hi!</div></div>
                : activeMessages.map((c,i)=>{
                    const mine = c.sender===currentUser?.username;
                    return (
                      <div key={i} style={s.msgRow(mine)}
                        onClick={() => { setShowEmojiFor(null); setMsgContextMenu(null); }}
                      >
                        {!mine && <div style={s.avatar(avatarColor(activeContact))}>{activeContact[0].toUpperCase()}</div>}
                        <div style={s.bubbleWrap}>
                          {/* Reply preview */}
                          {c.replyTo && (
                            <div style={{ background:'rgba(255,255,255,0.07)', borderLeft:'3px solid #6366f1', borderRadius:'8px 8px 0 0', padding:'6px 10px', fontSize:11, color:'#94a3b8', marginBottom:2 }}>
                              <span style={{ color:'#818cf8', fontWeight:600 }}>{c.replyTo.sender}: </span>
                              {c.replyTo.fileType ? `📎 ${c.replyTo.fileType}` : c.replyTo.text?.slice(0,60)}
                            </div>
                          )}
                          <div style={{ position:'relative' }}>
                            <div style={s.bubble(mine)}
                              onContextMenu={e => { e.preventDefault(); setMsgContextMenu({ msgId: c._id, x: e.clientX, y: e.clientY, seenAt: c.seenAt, mine }); }}
                            >
                              {c.fileType === 'image' && <img src={c.fileUrl} alt="img" style={{ maxWidth:'100%', borderRadius:8, display:'block', marginBottom: c.text?6:0 }} />}
                              {c.fileType === 'video' && <video src={c.fileUrl} controls style={{ maxWidth:'100%', borderRadius:8, display:'block', marginBottom: c.text?6:0 }} />}
                              {c.fileType === 'audio' && <audio src={c.fileUrl} controls style={{ width:'100%', marginBottom: c.text?6:0 }} />}
                              {c.fileType === 'file' && <a href={c.fileUrl} target="_blank" rel="noreferrer" style={{ color:'#a5b4fc', fontSize:13, display:'block', marginBottom: c.text?6:0 }}>📎 {c.fileName}</a>}
                              {c.text && <span>{c.text}</span>}
                              {!c.text && !c.fileType && <span style={{color:'#94a3b8',fontSize:12}}>📎 File</span>}
                            </div>
                            {/* Action buttons on hover/tap */}
                            <div style={{ display:'flex', gap:4, marginTop:4, justifyContent: mine?'flex-end':'flex-start' }}>
                              <button onClick={e=>{ e.stopPropagation(); setShowEmojiFor(showEmojiFor===c._id?null:c._id); }}
                                style={{ background:'none', border:'none', fontSize:14, cursor:'pointer', opacity:0.6, padding:'2px 4px' }}>😊</button>
                              <button onClick={e=>{ e.stopPropagation(); setReplyingTo(c); }}
                                style={{ background:'none', border:'none', fontSize:12, cursor:'pointer', opacity:0.6, color:'#94a3b8', padding:'2px 4px' }}>↩ Reply</button>
                            </div>
                            {/* Emoji picker */}
                            {showEmojiFor === c._id && (
                              <div onClick={e=>e.stopPropagation()} style={{ position:'absolute', [mine?'right':'left']:0, bottom:40, background:'#1e1e2e', border:'1px solid #2d2d3f', borderRadius:12, padding:'8px 10px', display:'flex', gap:8, zIndex:50, boxShadow:'0 8px 24px rgba(0,0,0,.5)' }}>
                                {['❤️','😂','😮','😢','👍','🔥'].map(emoji => (
                                  <button key={emoji} onClick={()=>reactToMsg(c._id, emoji)}
                                    style={{ background:'none', border:'none', fontSize:22, cursor:'pointer', transition:'transform .1s' }}>{emoji}</button>
                                ))}
                              </div>
                            )}
                          </div>
                          {/* Reactions display */}
                          {c.reactions?.length > 0 && (
                            <div style={{ display:'flex', gap:4, flexWrap:'wrap', marginTop:4, justifyContent: mine?'flex-end':'flex-start' }}>
                              {Object.entries(c.reactions.reduce((acc, r) => { acc[r.emoji] = (acc[r.emoji]||0)+1; return acc; }, {})).map(([emoji, count]) => (
                                <span key={emoji} onClick={()=>reactToMsg(c._id, emoji)}
                                  style={{ background:'#1e1e2e', border:'1px solid #2d2d3f', borderRadius:20, padding:'2px 8px', fontSize:12, cursor:'pointer' }}>
                                  {emoji} {count > 1 ? count : ''}
                                </span>
                              ))}
                            </div>
                          )}
                          <div style={s.msgMeta(mine)}>
                            <span style={s.msgTime}>{c.time}</span>
                            {c.sentiment && c.text && <span style={s.sentimentBadge(c.sentiment)}>{c.sentiment}</span>}
                          </div>
                        </div>
                        {mine && <div style={s.avatar('linear-gradient(135deg,#6366f1,#8b5cf6)')}>{currentUser.username[0].toUpperCase()}</div>}
                      </div>
                    );
                  })
              }
              <div ref={messagesEndRef}/>
            </div>

            {notification && <div style={s.notifBanner}>{notification}</div>}
            {warning && <div style={s.warningBanner}>⚠️ {warning}</div>}

            {/* Right click context menu */}
            {msgContextMenu && (
              <div onClick={()=>setMsgContextMenu(null)} style={{ position:'fixed', inset:0, zIndex:200 }}>
                <div onClick={e=>e.stopPropagation()} style={{ position:'fixed', top: Math.min(msgContextMenu.y, window.innerHeight-120), left: Math.min(msgContextMenu.x, window.innerWidth-200), background:'#1e1e2e', border:'1px solid #2d2d3f', borderRadius:10, padding:'8px 0', minWidth:180, boxShadow:'0 8px 24px rgba(0,0,0,.5)', zIndex:201 }}>
                  {msgContextMenu.mine && (
                    <div style={{ padding:'10px 16px', fontSize:13, color: msgContextMenu.seenAt ? '#4ade80' : '#64748b', borderBottom:'1px solid #2d2d3f' }}>
                      {msgContextMenu.seenAt
                        ? `✅ Seen at ${new Date(msgContextMenu.seenAt).toLocaleTimeString([], { hour:'2-digit', minute:'2-digit' })}`
                        : '🕐 Not seen yet'}
                    </div>
                  )}
                  <div style={{ padding:'10px 16px', fontSize:13, color:'#e2e8f0', cursor:'pointer' }}
                    onClick={()=>{ const m = activeMessages.find(m=>m._id===msgContextMenu.msgId); if(m) setReplyingTo(m); setMsgContextMenu(null); }}>
                    ↩ Reply
                  </div>
                  <div style={{ padding:'10px 16px', fontSize:13, color:'#e2e8f0', cursor:'pointer', borderTop:'1px solid #2d2d3f' }}
                    onClick={()=>{ setShowEmojiFor(msgContextMenu.msgId); setMsgContextMenu(null); }}>
                    😊 React
                  </div>
                </div>
              </div>
            )}

            {smartReplies.length > 0 && (
              <div style={{margin:'0 20px 10px', display:'flex', gap:8, flexWrap:'wrap', flexShrink:0}}>
                <span style={{fontSize:11, color:'#818cf8', fontWeight:700, alignSelf:'center', flexShrink:0}}>💡</span>
                {smartReplies.map((r, i) => (
                  <button key={i}
                    style={{background:'#1e1e3f', border:'1px solid #4338ca', color:'#c7d2fe', fontSize:12, padding:'6px 14px', borderRadius:20, cursor:'pointer', fontWeight:500, whiteSpace:'nowrap'}}
                    onClick={() => send(r)}
                  >{r}</button>
                ))}
                <button style={{background:'transparent', border:'none', color:'#475569', cursor:'pointer', fontSize:16, alignSelf:'center'}} onClick={() => setSmartReplies([])}>✕</button>
              </div>
            )}

            <div style={s.inputArea}>
              {replyingTo && (
                <div style={{ position:'absolute', bottom:'100%', left:0, right:0, background:'#1a1a2e', borderTop:'1px solid #312e81', padding:'8px 16px', display:'flex', alignItems:'center', justifyContent:'space-between' }}>
                  <div style={{ fontSize:12, color:'#818cf8' }}>
                    <span style={{ fontWeight:600 }}>↩ {replyingTo.sender}: </span>
                    <span style={{ color:'#94a3b8' }}>{replyingTo.fileType ? `📎 ${replyingTo.fileType}` : replyingTo.text?.slice(0,50)}</span>
                  </div>
                  <button onClick={()=>setReplyingTo(null)} style={{ background:'none', border:'none', color:'#475569', cursor:'pointer', fontSize:16 }}>✕</button>
                </div>
              )}
              <input type="file" ref={fileInputRef} style={{ display:'none' }} onChange={e => { sendFile(e.target.files[0]); e.target.value=''; }} />
              <button onClick={() => fileInputRef.current.click()} style={{ padding:'11px 14px', background:'#1e1e2e', border:'1px solid #2d2d3f', borderRadius:12, color:'#64748b', cursor:'pointer', fontSize:18, flexShrink:0 }} title="Send file">📎</button>
              <textarea style={s.inputBox} rows={1} value={msg} onChange={e=>setMsg(e.target.value)} onKeyDown={handleKey} onFocus={handleFocus} placeholder={`Message ${activeContact}...`}/>
              <button style={s.sendBtn(!!msg.trim())} onClick={()=>send()}>Send ➤</button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
